#include <cstdio>
#include <cstring>
#include <cstdlib>
#include <algorithm>
#include <cmath>
using namespace std;
typedef long long LL;
const LL INF = 1e15;
struct N { LL x, c, w; } a[11000];
bool cmp(N n1, N n2) { return n1.x < n2.x; }
LL f[510][11100];
int n, m, K;
LL d[11000], q[11000], h, t;

int main() {
    scanf("%d%d%d", &K, &m, &n);
    for (int i = 1; i <= n; i++) scanf("%lld%lld%lld", &a[i].x, &a[i].c, &a[i].w);
    n++; a[n].x = m;
    sort(a + 1, a + 1 + n, cmp);
    for (int i = 2; i <= n; i++) d[i] = a[i].x - a[i - 1].x;
    for (int i = 0; i <= n; i++) for (int j = 0; j <= K; j++) f[i][j] = INF;
    f[0][0] = 0;
    for (LL i = 1; i <= n; i++) {
        h = t = 0;
        for (LL j = 0; j <= K; j++) {
            while (h < t && j - q[h] > a[i - 1].c) h++;
            if (f[i - 1][j] != INF) {
                while (h < t) {
                    LL k = q[t - 1];
                    if (f[i - 1][k] - k * a[i - 1].w < f[i - 1][j] - j * a[i - 1].w) break;
                    t--;
                }
                q[t++] = j;
            }
            if (h < t) {
                LL k = q[h];
                f[i][j] = f[i - 1][k] + (j - k) * a[i - 1].w + j * j * d[i];
            }
        }
    }
    printf("%lld\n", f[n][K]);
    return 0;
}
